import React, { useState } from "react";

function App() {
  const [songs, setSongs] = useState([]);

  const musicData = {
    Happy: [
      "Butta Bomma 🎶",
      "Samajavaragamana 🎶",
      "Inkem Inkem Kavale 🎶"
    ],
    Sad: [
      "Oosupodu 🎶",
      "Yedhalo Oka Mounam 🎶",
      "Kanulanu Thaake 🎶"
    ],
    Love: [
      "Ninnu Kori 🎶",
      "Vachindamma 🎶",
      "Priyathama Priyathama 🎶"
    ],
    Motivation: [
      "Life of Ram 🎶",
      "Seethakaalam 🎶",
      "Nee Prashnalu 🎶"
    ],
    Relax: [
      "Nee Kallalona 🎶",
      "Oka Manasu 🎶",
      "Hrudhayam Jaripe 🎶"
    ],
    Party: [
      "Ramuloo Ramulaa 🎶",
      "Daang Daang 🎶",
      "Pakka Local 🎶"
    ],
    Devotional: [
      "Hanuman Chalisa 🎶",
      "Om Namah Shivaya 🎶",
      "Bhaja Govindam 🎶"
    ]
  };

  const showSongs = (mood) => {
    setSongs(musicData[mood]);
  };

  return (
    <div
      style={{
        textAlign: "center",
        minHeight: "100vh",
        padding: "20px",
        background: "linear-gradient(to right, #1e3c72, #2a5298)",
        color: "white"
      }}
    >
      <h1>🎧 Telugu Mood Music Recommender</h1>

      <p>Select your mood and enjoy Telugu songs 🎶</p>

      {/* Mood Buttons */}
      <div style={{ margin: "20px" }}>
        {Object.keys(musicData).map((mood, index) => (
          <button
            key={index}
            onClick={() => showSongs(mood)}
            style={{
              margin: "8px",
              padding: "10px 15px",
              borderRadius: "10px",
              border: "none",
              cursor: "pointer",
              backgroundColor: "#ffcc00",
              fontWeight: "bold"
            }}
          >
            {mood}
          </button>
        ))}
      </div>

      {/* Songs Display */}
      <div>
        <h2>🎶 Songs List</h2>

        {songs.length === 0 ? (
          <p>Select a mood to see songs</p>
        ) : (
          songs.map((song, index) => (
            <p
              key={index}
              style={{
                background: "rgba(255,255,255,0.2)",
                padding: "10px",
                margin: "10px auto",
                width: "300px",
                borderRadius: "10px"
              }}
            >
              {song}
            </p>
          ))
        )}
      </div>
    </div>
  );
}

export default App;
